import { fileURLToPath } from "node:url";
function getPackageRoot() {
  const currentFile = fileURLToPath(import.meta.url);
  const currentDir = dirname(currentFile);
  const debug = process.env.DEBUG_INSTALL === "1";
  if (debug) {
    console.log(`[DEBUG] import.meta.url: ${import.meta.url}`);
    console.log(`[DEBUG] currentFile: ${currentFile}`);
    console.log(`[DEBUG] currentDir: ${currentDir}`);
  }
  let root = dirname(currentDir);
  if (debug)
    console.log(`[DEBUG] Trying root (1 up): ${root}, has package.json: ${existsSync2(join2(root, "package.json"))}`);
  if (!existsSync2(join2(root, "package.json"))) {
    root = dirname(root);
    if (debug)
      console.log(`[DEBUG] Trying root (2 up): ${root}, has package.json: ${existsSync2(join2(root, "package.json"))}`);
  }
  if (!existsSync2(join2(root, "package.json"))) {
    root = dirname(root);
    if (debug)
      console.log(`[DEBUG] Trying root (3 up): ${root}, has package.json: ${existsSync2(join2(root, "package.json"))}`);
  }
  if (debug)
    console.log(`[DEBUG] Final root: ${root}`);
  return root;
}
