function createFormatters(useColor) {
  const colored = useColor ?? process.stdout.isTTY !== false;
  const c = {
    reset: colored ? "\x1B[0m" : "",
    bold: colored ? "\x1B[1m" : "",
    dim: colored ? "\x1B[2m" : "",
    green: colored ? "\x1B[32m" : "",
    red: colored ? "\x1B[31m" : "",
    yellow: colored ? "\x1B[33m" : "",
    cyan: colored ? "\x1B[36m" : "",
    blue: colored ? "\x1B[34m" : "",
    magenta: colored ? "\x1B[35m" : ""
  };
  return {
    c,
    ok: (text) => `${c.green}✓${c.reset} ${text}`,
    fail: (text) => `${c.red}✗${c.reset} ${text}`,
    warn: (text) => `${c.yellow}⚠${c.reset} ${text}`,
    header: (text) => `
${c.bold}${text}${c.reset}`,
    subheader: (text) => `${c.bold}${text}${c.reset}`,
    dimText: (text) => `${c.dim}${text}${c.reset}`
  };
}

