// src/cli/commands/core/doctor/check-recommendations.ts
async function checkRecommendationsZone(ctx, installStatus) {
  const { ok, warn, header, c } = ctx.formatters;
  console.log(`
${header("Recommendations:")}`);
  const providers = getProvidersStatus();
  const oauthTypes = new Set(["openai-oauth"]);
  const unconfiguredApiKey = Object.entries(providers).filter(([_, info]) => !info.configured && info.type !== "claude-subscription" && !oauthTypes.has(info.type)).map(([name]) => name);
  const unconfiguredOAuth = Object.entries(providers).filter(([_, info]) => !info.configured && oauthTypes.has(info.type)).map(([name]) => name);
  if (unconfiguredApiKey.length > 0) {
    console.log(`  ${warn(`Set API keys for: ${c.yellow}${unconfiguredApiKey.join(", ")}${c.reset}`)}`);
    if (ctx.detail) {
      for (const provider of unconfiguredApiKey) {
        console.log(`    ${c.dim}export ${provider.toUpperCase()}_API_KEY=your-key${c.reset}`);
      }
    }
  }
  if (unconfiguredOAuth.length > 0) {
    console.log(`  ${warn(`Authenticate OAuth: ${c.yellow}${unconfiguredOAuth.join(", ")}${c.reset}`)}`);
    if (ctx.detail) {
      for (const provider of unconfiguredOAuth) {
        console.log(`    ${c.dim}oh-my-claude auth login ${provider}${c.reset}`);
      }
    }
  }
  if (unconfiguredApiKey.length === 0 && unconfiguredOAuth.length === 0) {
    console.log(`  ${ok("All providers configured")}`);
  }
  if (!installStatus.installed) {
    console.log(`  ${warn("Run 'oh-my-claude install' to complete setup")}`);
  }
}

// src/cli/commands/core/doctor/index.ts
function registerDoctorCommand(program2) {
  program2.command("doctor").description("Diagnose oh-my-claude configuration").option("--detail", "Show detailed status of each component").option("--fix-mem", "Fix memory system issues (copy WASM, rebuild index)").option("--no-color", "Disable colored output").action(async (options) => {
    const detail = options.detail;
    const fixMem = !!options.fixMem;
    const useColor = options.color !== false && process.stdout.isTTY;
    const formatters = createFormatters(useColor);
    const { c, dimText } = formatters;
    const projectRoot = findProjectRoot2();
    const ctx = { detail, fixMem, formatters, projectRoot };
    console.log(`${c.bold}${c.magenta}oh-my-claude Doctor${c.reset}
`);
    const installStatus = await checkInstallationZone(ctx);
    if (detail) {
      await checkComponentsZone(ctx);
      await checkCompanionsZone(ctx);
    }
    await checkProvidersZone(ctx);
    await checkConfigZone(ctx);
    await checkMemoryZone(ctx);
    await checkRecommendationsZone(ctx, installStatus);
    if (!detail && !fixMem) {
      console.log(`
${dimText("Tip: Run 'oh-my-claude doctor --detail' for detailed component status")}`);
    }
  });
}

