function extractProxySessionId() {
  const baseUrl = process.env.ANTHROPIC_BASE_URL;
  if (!baseUrl)
    return;
  try {
    const url = new URL(baseUrl);
    const match = url.pathname.match(/^\/s\/([a-zA-Z0-9_-]+)\/?/);
    return match ? match[1] : undefined;
  } catch {
    return;
  }
}
async function getSessionState(controlPort, sessionId) {
  try {
    const resp = await fetch(`http://localhost:${controlPort}/status?session=${sessionId}`, { signal: AbortSignal.timeout(1000) });
    if (!resp.ok)
      return null;
    const data = await resp.json();
    return {
      switched: data.switched ?? false,
      provider: data.provider,
      model: data.model
    };
  } catch {
    return null;
  }
}
function formatAge(startedAt) {
  const age = Math.floor((Date.now() - startedAt) / 1000);
  if (age < 60)
    return `${age}s`;
  if (age < 3600)
    return `${Math.floor(age / 60)}m`;
  return `${Math.floor(age / 3600)}h ${Math.floor(age % 3600 / 60)}m`;
}
async function enrichSessions(entries) {
  const results = await Promise.all(entries.map(async (entry) => {
    const state = await getSessionState(entry.controlPort, entry.sessionId);
    return { ...entry, state: state ?? undefined };
  }));
  return results;
}
