function deriveSessionIdentity(cwd2) {
  const hash = createHash3("sha256").update(cwd2).digest();
  const sessionId = hash.subarray(0, 4).toString("hex");
  const port = 20000 + hash.readUInt16BE(4) % 30000;
  return {
    sessionId,
    preferredPort: port,
    preferredControlPort: port + 1
  };
}
