var CREDS_PATH3 = join41(homedir28(), ".claude", "oh-my-claude", "aliyun-creds.json");
function getLoginScriptPath3() {
  return join41(homedir28(), ".claude", "oh-my-claude", "scripts", "aliyun-login.ts");
}
async function loginAliyun() {
  return new Promise((resolve) => {
    console.log(`
=== Aliyun Bailian Login ===
`);
    console.log("This will open a browser window.");
    console.log(`Please login with your Aliyun account.
`);
    const scriptPath = getLoginScriptPath3();
    const installDir = join41(homedir28(), ".claude", "oh-my-claude");
    const playwrightDir = join41(installDir, "node_modules", "playwright");
    try {
      const needsPlaywright = !existsSync40(playwrightDir);
      const needsTsx = !existsSync40(join41(installDir, "node_modules", "tsx"));
      if (needsPlaywright || needsTsx) {
        const pkgs = [];
        if (needsPlaywright)
          pkgs.push("playwright");
        if (needsTsx)
          pkgs.push("tsx");
        console.log(`Installing ${pkgs.join(" + ")} (first-time setup, this may take a moment)...
`);
        const installResult = spawnSync9("bun", ["add", "--ignore-scripts", ...pkgs], {
          cwd: installDir,
          stdio: "inherit",
          shell: true
        });
        if (installResult.status !== 0) {
          resolve({
            success: false,
            error: `Failed to install dependencies. Run manually: cd ~/.claude/oh-my-claude && bun add --ignore-scripts ${pkgs.join(" ")}`
          });
          return;
        }
      }
    } catch {
      resolve({
        success: false,
        error: "Failed to install playwright dependency"
      });
      return;
    }
    const result = spawnSync9("npx", ["--yes", "tsx", scriptPath], {
      cwd: installDir,
      stdio: "inherit",
      shell: true,
      env: { ...process.env, NODE_PATH: join41(installDir, "node_modules") }
    });
    if (result.status !== 0) {
      resolve({
        success: false,
        error: `Login script failed with code ${result.status}`
      });
      return;
    }
    if (!existsSync40(CREDS_PATH3)) {
      resolve({
        success: false,
        error: "Credentials file not found after login"
      });
      return;
    }
    try {
      const creds = JSON.parse(readFileSync28(CREDS_PATH3, "utf-8"));
      resolve({
        success: true,
        credential: creds
      });
    } catch {
      resolve({
        success: false,
        error: "Failed to parse credentials file"
      });
    }
  });
}
