  console.log(`  escape-time      ${c.cyan}0${c.reset}         (no delay for Esc key)`);
  console.log(`  default-terminal ${c.cyan}screen-256color${c.reset}`);
  console.log(`  mode-keys        ${c.cyan}vi${c.reset}        (vi-style copy mode)`);
