var PSMUX_MARKER = "# oh-my-claude psmux config";
function detectBashPath() {
  if (process.platform !== "win32")
    return null;
  const candidates = [
    "D:/Applications/Git/usr/bin/bash.exe",
    "C:/Program Files/Git/usr/bin/bash.exe",
    "C:/Program Files (x86)/Git/usr/bin/bash.exe"
  ];
  try {
    const result = execSync19("where bash.exe", {
      encoding: "utf-8",
      stdio: ["ignore", "pipe", "ignore"]
    }).trim();
    if (result) {
      const first = result.split(`
`)[0]?.trim();
      if (first)
        candidates.unshift(first.replace(/\\/g, "/"));
    }
  } catch {}
  for (const p of candidates) {
    if (existsSync45(p))
      return p;
  }
  return null;
}
function buildPsmuxConfig(bashPath) {
  return `${PSMUX_MARKER}
# Generated by: oh-my-claude terminal-config psmux
# Docs: https://github.com/lgcyaxi/oh-my-claude
#
# Claude Code team agents send bash-style commands to panes:
#   cd '...' && env VAR=val claude.exe --agent-id ...
# psmux defaults to PowerShell, which can't parse these.
# Setting default-shell to Git Bash (with --login for PATH) fixes this.

set -g default-shell "${bashPath} --login"
`;
}
function runPsmuxAction(options = {}) {
  const { c, ok, fail, warn, dimText } = createFormatters();
  if (process.platform !== "win32") {
    console.log(dimText("psmux is Windows-only. Use 'oh-my-claude terminal-config tmux' instead."));
    return;
  }
  let psmuxVersion = "";
  try {
    psmuxVersion = execSync19("psmux --version", {
      encoding: "utf-8",
      stdio: ["ignore", "pipe", "ignore"]
    }).trim();
  } catch {
    console.log(fail("psmux is not installed."));
    console.log(dimText("Install via: winget install psmux"));
    process.exit(1);
  }
  const bashPath = detectBashPath();
  if (!bashPath) {
    console.log(fail("Git Bash not found."));
    console.log(dimText("Install Git for Windows: https://git-scm.com/download/win"));
    process.exit(1);
  }
  const config = buildPsmuxConfig(bashPath);
  console.log(`${c.bold}oh-my-claude terminal-config psmux${c.reset}  (${psmuxVersion})`);
  console.log(dimText(`Bash: ${bashPath}
`));
  if (options.show) {
    console.log(config);
    return;
  }
  const confPath = join46(homedir34(), ".psmux.conf");
  const existing = existsSync45(confPath);
  if (existing && !options.force) {
    const content = readFileSync33(confPath, "utf-8");
    if (content.includes(PSMUX_MARKER)) {
      console.log(ok("oh-my-claude psmux config already present in ~/.psmux.conf"));
      return;
    }
    console.log(warn("~/.psmux.conf already exists."));
    console.log(dimText("Use --force to overwrite."));
    return;
  }
  if (existing) {
    const backupPath = `${confPath}.bak`;
    copyFileSync8(confPath, backupPath);
    console.log(dimText(`Backed up existing config to ${backupPath}`));
  }
  writeFileSync21(confPath, config, "utf-8");
  console.log(ok(`Created ${confPath}`));
  console.log();
  console.log(`${c.bold}Setting:${c.reset}`);
  console.log(`  default-shell  ${c.cyan}${bashPath} --login${c.reset}`);
  console.log();
  console.log(dimText("Restart psmux sessions for this to take effect."));
  try {
    execSync19(`tmux set -g default-shell "${bashPath} --login"`, {
      encoding: "utf-8",
      stdio: ["ignore", "pipe", "ignore"]
    });
    console.log(ok("Applied to running psmux session"));
  } catch {}
}
function registerTerminalConfigCommand(program2) {
  const cmd = program2.command("terminal-config").alias("tc").description("Write terminal configuration for Claude Code sessions").action(() => {
    if (process.platform === "win32") {
      runPsmuxAction();
    } else {
      runTmuxAction();
    }
  });
  cmd.command("tmux").description("Write recommended tmux configuration for Claude Code sessions").option("--show", "Show the config without writing").option("--force", "Overwrite existing .tmux.conf without backup").option("--append", "Append to existing .tmux.conf instead of replacing").action((options) => {
    runTmuxAction(options);
  });
  cmd.command("psmux").description("Write psmux configuration for Claude Code team agents on Windows").option("--show", "Show the config without writing").option("--force", "Overwrite existing .psmux.conf").action((options) => {
    runPsmuxAction(options);
  });
}

